package com.mds.cache.enumerator;

/**
 * Enumeration of SLF4J log levels used by
 * {@link com.mds.cache.factory.LoggerFactory} to dispatch cache-related
 * log messages at the desired severity.
 *
 * @author MDS
 * @since 0.0.1-SNAPSHOT
 */
public enum LogLevel {
  INFO,
  DEBUG,
  WARN,
  ERROR,
  TRACE
}
